const text = $input.item.json.message?.text || '';
const lines = text.split('\n').map(l => l.trim());

let jobTitle = '', location = '', remote = false, seniority = 'Mid', platforms = ['LinkedIn', 'Indeed'], userEmail = '', telegramChatId = $input.item.json.message?.chat?.id || '';

for (const line of lines) {
  if (line.toLowerCase().includes('job:') || line.toLowerCase().includes('title:')) jobTitle = line.split(':')[1]?.trim() || '';
  if (line.toLowerCase().includes('location:')) location = line.split(':')[1]?.trim() || '';
  if (line.toLowerCase().includes('remote:')) remote = line.toLowerCase().includes('true') || line.toLowerCase().includes('yes');
  if (line.toLowerCase().includes('seniority:')) seniority = line.split(':')[1]?.trim() || 'Mid';
  if (line.toLowerCase().includes('platforms:')) platforms = line.split(':')[1]?.split(',').map(p => p.trim()) || ['LinkedIn', 'Indeed'];
  if (line.toLowerCase().includes('email:')) userEmail = line.split(':')[1]?.trim() || '';
}

return [{ json: { jobTitle, location, remote, seniority, platforms, userEmail, telegramChatId } }];

const response = $input.item.json;
const jobsData = response.data || [];
const userPlatforms = $('Normalize Fields').item.json.platforms || [];

const formattedJobs = jobsData.map(job => ({
  job_id: job.job_id,
  job_title: job.job_title,
  company_name: job.employer_name,
  location: `${job.job_city || ''} ${job.job_country || ''}`.trim(),
  remote: job.job_is_remote || false,
  apply_link: job.job_apply_link,
  job_description: (job.job_description || '').substring(0, 400),
  date_posted: job.job_posted_at_datetime_utc,
  platform_source: job.job_publisher
})).filter(job => userPlatforms.length === 0 || userPlatforms.some(platform => job.platform_source?.toLowerCase().includes(platform.toLowerCase())));

return formattedJobs.map(job => ({ json: job }));

const jobs = $input.item.json; const jobCount = Array.isArray(jobs) ? jobs.length : (jobs.job_title ? 1 : 0); let message = `🎯 Job Search Results

`; message += `Found ${jobCount} relevant job${jobCount !== 1 ? 's' : ''} matching your criteria!

`; if (jobCount === 0) { message += 'No jobs found matching your preferences. Try adjusting your search criteria.'; } else { const jobArray = Array.isArray(jobs) ? jobs : [jobs]; jobArray.slice(0, 10).forEach((job, index) => { message += `${index + 1}. ${job.job_title || 'N/A'}
`; message += `   🏢 ${job.company_name || 'N/A'}
`; message += `   📍 ${job.location || 'N/A'}
`; message += `   ⭐ AI Score: ${job.score || 0}/10
`; message += `   💡 ${job.fitSummary || job.reason || ''}
`; message += `   🔗 ${job.apply_link || 'N/A'}

`; }); if (jobCount > 10) { message += `... and ${jobCount - 10} more jobs in your Google Sheet!`; } } const chatId = $('Normalize Fields').item.json.telegramChatId; return [{ json: { chatId, message } }];

const newJobs = $('Filter Jobs from Last 10 Minutes').all().map(item => item.json);
const existingJobIds = new Set($('Get All Existing Job IDs').all().map(item => item.json.job_id));
const uniqueJobs = newJobs.filter(job => !existingJobIds.has(job.job_id));
return uniqueJobs.map(job => ({ json: job }));

const jobs = $input.all().map(item => item.json); const count = jobs.length; let message = `🔔 *NEW JOBS ALERT!*
${count} new posting${count > 1 ? 's' : ''} in last 10 min

`; jobs.forEach((job, index) => { message += `${index + 1}. *${job.job_title}*
🏢 ${job.company_name}
📍 ${job.location}${job.remote ? ' | 🌐 Remote' : ''}
🕐 Posted: ${job.date_posted}
🔗 Apply: ${job.apply_link}

`; }); message += '✅ Saved to your job tracker sheet.'; return [{ json: { message } }];

const applyLink = $input.item.json.apply_link || '';
let linkedinJobId = '';

// Extract numeric job ID from LinkedIn URL
// Common patterns: /jobs/view/123456789/ or ?currentJobId=123456789
const viewMatch = applyLink.match(/\/jobs\/view\/(\d+)/);
const queryMatch = applyLink.match(/currentJobId=(\d+)/);

if (viewMatch) {
  linkedinJobId = viewMatch[1];
} else if (queryMatch) {
  linkedinJobId = queryMatch[1];
}

return [{
  json: {
    linkedinJobId: linkedinJobId,
    job_id: $input.item.json.job_id || '',
    job_title: $input.item.json.job_title || '',
    company_name: $input.item.json.company_name || '',
    location: $input.item.json.location || '',
    apply_link: applyLink,
    job_description: $input.item.json.job_description || ''
  }
}];

