Resume:
{{ $("Parse Resume Text").item.json.text }}

Job Title: {{ $("Extract LinkedIn Job ID").item.json.job_title }}
Company: {{ $("Extract LinkedIn Job ID").item.json.company_name }}
Job Description: {{ $json.text }}

