const aiOutput = $input.item.json.output || $input.item.json.text || '';
let parsed;

try {
  // Try to extract JSON from the AI response
  const jsonMatch = aiOutput.match(/\{[^}]+\}/s);
  parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : JSON.parse(aiOutput);
} catch (e) {
  // Fallback if parsing fails
  parsed = {
    coverLetter: '',
    phone: '',
    currentLocation: '',
    yearsOfExperience: 0,
    willingToRelocate: false,
    expectedSalary: '',
    linkedinHeadline: '',
    whyThisRole: ''
  };
}

// Get data from previous nodes
const linkedinJobId = $('Extract LinkedIn Job ID').item.json.linkedinJobId || '';
const job_id = $('Extract LinkedIn Job ID').item.json.job_id || '';
const company_name = $('Extract LinkedIn Job ID').item.json.company_name || '';
const job_title = $('Extract LinkedIn Job ID').item.json.job_title || '';
const resumeText = $('Parse Resume Text').item.json.text || '';

// Build LinkedIn Easy Apply POST body
const applicationBody = {
  jobId: linkedinJobId,
  resume: resumeText,
  coverLetter: parsed.coverLetter || '',
  phone: parsed.phone || '',
  currentLocation: parsed.currentLocation || '',
  yearsOfExperience: parsed.yearsOfExperience || 0,
  willingToRelocate: parsed.willingToRelocate || false,
  expectedSalary: parsed.expectedSalary || '',
  linkedinHeadline: parsed.linkedinHeadline || '',
  whyThisRole: parsed.whyThisRole || ''
};

return [{
  json: {
    applicationBody: applicationBody,
    coverLetter: parsed.coverLetter || '',
    linkedinJobId: linkedinJobId,
    job_id: job_id,
    company_name: company_name,
    job_title: job_title
  }
}];

